package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

public class JsonTreeReaderTest {

  private JsonTreeReader reader;

  @BeforeEach
  public void setUp() throws Exception {
    // Create a JsonElement stub for constructor
    JsonElement element = mock(JsonElement.class);
    reader = new JsonTreeReader(element);
  }

  @Test
  public void testSkipValue_NAME_invokesNextName() throws Exception {
    JsonTreeReader spyReader = Mockito.spy(reader);
    doReturn(JsonToken.NAME).when(spyReader).peek();

    spyReader.skipValue();

    // nextName(boolean) is private, use reflection to verify it was called
    Method nextNameMethod = JsonTreeReader.class.getDeclaredMethod("nextName", boolean.class);
    nextNameMethod.setAccessible(true);
    verify(spyReader).peek();
    // Cannot verify private method call directly via Mockito, so instead invoke and check no exception
    // Alternatively, we can spy and override nextName(boolean) to track calls, but here just call skipValue to cover
  }

  @Test
  public void testSkipValue_END_ARRAY_invokesEndArray() throws Exception {
    JsonTreeReader spyReader = Mockito.spy(reader);
    doReturn(JsonToken.END_ARRAY).when(spyReader).peek();

    spyReader.skipValue();

    verify(spyReader).endArray();
  }

  @Test
  public void testSkipValue_END_OBJECT_invokesEndObject() throws Exception {
    JsonTreeReader spyReader = Mockito.spy(reader);
    doReturn(JsonToken.END_OBJECT).when(spyReader).peek();

    spyReader.skipValue();

    verify(spyReader).endObject();
  }

  @Test
  public void testSkipValue_END_DOCUMENT_doesNothing() throws Exception {
    JsonTreeReader spyReader = Mockito.spy(reader);
    doReturn(JsonToken.END_DOCUMENT).when(spyReader).peek();

    spyReader.skipValue();

    // popStack() is private, cannot verify directly, so verify no interactions with popStack via reflection
    // Instead, verify stackSize and pathIndices unchanged
    int stackSize = getPrivateField(spyReader, "stackSize");
    int[] pathIndices = getPrivateField(spyReader, "pathIndices");
    assertEquals(stackSize, getPrivateField(spyReader, "stackSize"));
    assertEquals(0, pathIndices[0]);
  }

  @Test
  public void testSkipValue_default_stackSizeZero_noIncrement() throws Exception {
    JsonTreeReader spyReader = Mockito.spy(reader);
    doReturn(JsonToken.BOOLEAN).when(spyReader).peek();

    // Set stackSize to 0 via reflection
    setPrivateField(spyReader, "stackSize", 0);

    // spy popStack by spying on the private method via reflection proxy
    spyReader.skipValue();

    // popStack() is private, cannot verify directly, but stackSize should remain 0
    int stackSize = getPrivateField(spyReader, "stackSize");
    assertEquals(0, stackSize);

    // pathIndices should not be incremented since stackSize == 0
    int[] pathIndices = getPrivateField(spyReader, "pathIndices");
    assertEquals(0, pathIndices[0]);
  }

  @Test
  public void testSkipValue_default_stackSizeGreaterThanZero_incrementsPathIndices() throws Exception {
    JsonTreeReader spyReader = Mockito.spy(reader);
    doReturn(JsonToken.STRING).when(spyReader).peek();

    // Set stackSize to 2 and pathIndices[1] = 5
    setPrivateField(spyReader, "stackSize", 2);
    int[] pathIndices = getPrivateField(spyReader, "pathIndices");
    pathIndices[1] = 5;

    spyReader.skipValue();

    // popStack() is private, cannot verify directly, but pathIndices[1] should increment by 1
    assertEquals(6, pathIndices[1]);
  }

  // Reflection helpers
  private void setPrivateField(Object instance, String fieldName, Object value) throws Exception {
    Field field = getField(instance.getClass(), fieldName);
    field.setAccessible(true);
    field.set(instance, value);
  }

  @SuppressWarnings("unchecked")
  private <T> T getPrivateField(Object instance, String fieldName) throws Exception {
    Field field = getField(instance.getClass(), fieldName);
    field.setAccessible(true);
    return (T) field.get(instance);
  }

  private Field getField(Class<?> clazz, String fieldName) throws NoSuchFieldException {
    while (clazz != null) {
      try {
        return clazz.getDeclaredField(fieldName);
      } catch (NoSuchFieldException e) {
        clazz = clazz.getSuperclass();
      }
    }
    throw new NoSuchFieldException(fieldName);
  }
}
